26	type Storage interface {
27		GetContractByID(ctx context.Context, contractID uuid.UUID) (*models.Contract, error)
28		UpdateContractStatus(ctx context.Context, requestID string, status models.ContractStatus) error
29		UpdateContractStatusByID(ctx context.Context, contractID uuid.UUID, status models.ContractStatus) error
30		UpdateContractLoanReference(ctx context.Context, requestID string, loanReference string) error
31		UpdateContractExpiresAt(ctx context.Context, contractID uuid.UUID, expiresAt time.Time) error
32	}
33	
34	type AccountClient interface {
35		GetAccount(ctx context.Context, in *accountgateway.GetAccountRequest, opts ...grpc.CallOption) (*accountgateway.GetAccountResponse, error)
36	}
37	
38	type LoanboxClient interface {
39		CreateLoan(ctx context.Context, req loanboxclient.CreateLoanRequest) (*loanboxclient.CreateLoanResponse, error)
40	}
